import {
  createRegistry,
  registerComponent,
  getRenderer,
  getDefaultRegistry,
  registerToDefault,
} from './index';
import type { SDUIComponentRenderer } from '../models';

const MockComponent: SDUIComponentRenderer = () => null;
const AnotherComponent: SDUIComponentRenderer = () => null;

describe('SDUI Registry', () => {
  describe('createRegistry', () => {
    it('creates an empty registry', () => {
      const registry = createRegistry();
      expect(Object.keys(registry)).toHaveLength(0);
    });

    it('creates a registry with initial components', () => {
      const registry = createRegistry({ heading: MockComponent });
      expect(registry.heading).toBe(MockComponent);
    });
  });

  describe('registerComponent', () => {
    it('adds a component to the registry', () => {
      const registry = createRegistry();
      const updated = registerComponent(registry, 'button', MockComponent);
      expect(updated.button).toBe(MockComponent);
    });

    it('does not mutate the original registry', () => {
      const registry = createRegistry();
      registerComponent(registry, 'button', MockComponent);
      expect(registry.button).toBeUndefined();
    });

    it('overwrites an existing component', () => {
      const registry = createRegistry({ button: MockComponent });
      const updated = registerComponent(registry, 'button', AnotherComponent);
      expect(updated.button).toBe(AnotherComponent);
    });
  });

  describe('getRenderer', () => {
    it('returns the renderer for a registered type', () => {
      const registry = createRegistry({ heading: MockComponent });
      expect(getRenderer(registry, 'heading')).toBe(MockComponent);
    });

    it('returns undefined for an unregistered type', () => {
      const registry = createRegistry();
      expect(getRenderer(registry, 'unknown')).toBeUndefined();
    });
  });

  describe('default registry', () => {
    afterEach(() => {
      const registry = getDefaultRegistry();
      for (const key of Object.keys(registry)) {
        delete registry[key];
      }
    });

    it('returns the registry object', () => {
      const registry = getDefaultRegistry();
      expect(registry).toBeDefined();
      expect(typeof registry).toBe('object');
    });

    it('registerToDefault adds to the default registry', () => {
      registerToDefault('test_component', MockComponent);
      const registry = getDefaultRegistry();
      expect(registry.test_component).toBe(MockComponent);
    });
  });
});

# Frontend Style Guide — Sem Parar (Zustand-only + Hook Component Pattern)

Welcome to the **Sem Parar Frontend Style Guide**.  
This version consolidates: **Zustand as the only state manager**, **Hook Component pattern** for Screens and Atomic components, **services architecture (SOLID)**, and an **cache pattern**.

> Sit down, have a cup of coffee and read this calmly. ☕

---

## :pushpin: Table of Contents

- [Introduction](#introduction)
- [Components & Screens — Hook Component Pattern](#components--screens--hook-component-pattern)
- [Atomic Components — Hook Component Pattern](#atomic-components--hook-component-pattern)
- [Project Organization](#project-organization)
- [Services Architecture](#services-architecture)
- [State Management (Zustand-only)](#state-management-zustand-only)
- [Routes Naming](#routes-naming)
- [Folder Naming Rules](#folder-naming-rules)
- [Code Standards](#code-standards)
- [Styles Patterns](#styles-patterns)
- [Cache Pattern](#cache-pattern)
- [Checklist](#checklist)

---

## Introduction

The goal of this guide is to ensure **consistency, testability and scalability** across our frontend projects.

Key decisions:

- **Zustand** is the **exclusive** global/shared state manager.
- UI follows the **Hook Component** pattern (logic hook + dumb view).
- Domain logic lives in **`/services`** with **SOLID** layering.
- Cache is **typed and reusable**.

---

## Components & Screens — Hook Component Pattern

Each screen is split into a logic hook and a render-only component.

```
screens/Home/
├── index.ts        # logic: export useHomeScreen()
├── view.tsx        # render: export default HomeScreen
└── Models/
    └── index.d.ts    # types (Props, State, Handlers, Return)
```

**Models/index.d.ts**

```ts
export interface HomeParams {
  welcome?: string;
}
export interface HomeState {
  greeting: string;
  isLoading: boolean;
}
export interface HomeHandlers {
  onPressCTA: () => void;
}
export type UseHomeReturn = HomeState & HomeHandlers;
```

