import type {
  SDUIActionHandler,
  SDUIActionContext,
  SDUIActionDeps,
  SDUIActionDescriptor,
} from '../models';
import {
  createActionRegistry,
  registerAction,
  getActionHandler,
  executeAction,
  executeActions,
  getDefaultActionRegistry,
  registerToDefaultActions,
} from './registry';

const noop: SDUIActionHandler = () => ({ success: true });
const failHandler: SDUIActionHandler = () => ({ success: false, error: 'fail' });

const mockActionContext: SDUIActionContext = {
  screen: { product: { name: 'Abastecimento' } as unknown as string },
  form: { points: 5000 },
  setForm: jest.fn(),
};

const mockDeps: SDUIActionDeps = {};

beforeEach(() => {
  jest.spyOn(console, 'warn').mockImplementation(() => {});
  jest.spyOn(console, 'error').mockImplementation(() => {});
});

afterEach(() => {
  jest.restoreAllMocks();
});

describe('createActionRegistry', () => {
  it('creates an empty registry', () => {
    const registry = createActionRegistry();
    expect(Object.keys(registry)).toHaveLength(0);
  });

  it('creates a registry with initial handlers', () => {
    const registry = createActionRegistry({ navigate: noop });
    expect(registry.navigate).toBe(noop);
  });
});

describe('registerAction', () => {
  it('adds a handler to the registry', () => {
    const registry = createActionRegistry();
    const updated = registerAction(registry, 'navigate', noop);
    expect(updated.navigate).toBe(noop);
  });

  it('does not mutate the original registry', () => {
    const registry = createActionRegistry();
    registerAction(registry, 'navigate', noop);
    expect(registry.navigate).toBeUndefined();
  });

  it('overwrites an existing handler', () => {
    const registry = createActionRegistry({ navigate: noop });
    const updated = registerAction(registry, 'navigate', failHandler);
    expect(updated.navigate).toBe(failHandler);
  });
});

describe('getActionHandler', () => {
  it('returns the handler for a registered type', () => {
    const registry = createActionRegistry({ goBack: noop });
    expect(getActionHandler(registry, 'goBack')).toBe(noop);
  });

  it('returns undefined for an unregistered type', () => {
    const registry = createActionRegistry();
    expect(getActionHandler(registry, 'unknown')).toBeUndefined();
  });
});

describe('executeAction', () => {
  it('calls the registered handler and returns result', async () => {
    const handler = jest.fn<ReturnType<SDUIActionHandler>, Parameters<SDUIActionHandler>>(
      () => ({ success: true, data: 'ok' }),
    );
    const registry = createActionRegistry({ navigate: handler });
    const descriptor: SDUIActionDescriptor = {
      type: 'navigate',
      payload: { screen: 'Home' },
    };

    const result = await executeAction(registry, descriptor, mockActionContext, mockDeps);

    expect(result.success).toBe(true);
    expect(result.data).toBe('ok');
    expect(handler).toHaveBeenCalledWith(
      { screen: 'Home' },
      mockActionContext,
      mockDeps,
    );
  });

  it('returns failure for unknown action types', async () => {
    const registry = createActionRegistry();
    const descriptor: SDUIActionDescriptor = { type: 'unknown' };

    const result = await executeAction(registry, descriptor, mockActionContext, mockDeps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('Unknown action type');
  });

  it('interpolates payload strings with merged context', async () => {
    const handler = jest.fn<ReturnType<SDUIActionHandler>, Parameters<SDUIActionHandler>>(
      () => ({ success: true }),
    );
    const registry = createActionRegistry({ navigate: handler });
    const descriptor: SDUIActionDescriptor = {
      type: 'navigate',
      payload: { screen: 'Detail', title: '{{product.name}}' },
    };

    await executeAction(registry, descriptor, mockActionContext, mockDeps);

    expect(handler).toHaveBeenCalledWith(
      { screen: 'Detail', title: 'Abastecimento' },
      mockActionContext,
      mockDeps,
    );
  });

  it('interpolates form values from merged context', async () => {
    const handler = jest.fn<ReturnType<SDUIActionHandler>, Parameters<SDUIActionHandler>>(
      () => ({ success: true }),
    );
    const registry = createActionRegistry({ submit: handler });
    const descriptor: SDUIActionDescriptor = {
      type: 'submit',
      payload: { value: '{{form.points}}' },
    };

    await executeAction(registry, descriptor, mockActionContext, mockDeps);

    expect(handler).toHaveBeenCalledWith(
      { value: '5000' },
      mockActionContext,
      mockDeps,
    );
  });

  it('catches handler errors and returns failure result', async () => {
    const throwing: SDUIActionHandler = () => {
      throw new Error('Handler exploded');
    };
    const registry = createActionRegistry({ boom: throwing });
    const descriptor: SDUIActionDescriptor = { type: 'boom' };

    const result = await executeAction(registry, descriptor, mockActionContext, mockDeps);

    expect(result.success).toBe(false);
    expect(result.error).toBe('Handler exploded');
  });

  it('catches async handler errors', async () => {
    const asyncThrowing: SDUIActionHandler = async () => {
      throw new Error('Async failure');
    };
    const registry = createActionRegistry({ asyncBoom: asyncThrowing });

    const result = await executeAction(
      registry,
      { type: 'asyncBoom' },
      mockActionContext,
      mockDeps,
    );

    expect(result.success).toBe(false);
    expect(result.error).toBe('Async failure');
  });

  it('handles undefined payload', async () => {
    const handler = jest.fn<ReturnType<SDUIActionHandler>, Parameters<SDUIActionHandler>>(
      () => ({ success: true }),
    );
    const registry = createActionRegistry({ goBack: handler });

    await executeAction(registry, { type: 'goBack' }, mockActionContext, mockDeps);

    expect(handler).toHaveBeenCalledWith(undefined, mockActionContext, mockDeps);
  });
});

describe('executeActions', () => {
  it('executes multiple actions sequentially', async () => {
    const order: string[] = [];
    const first: SDUIActionHandler = () => {
      order.push('first');
      return { success: true };
    };
    const second: SDUIActionHandler = () => {
      order.push('second');
      return { success: true };
    };
    const registry = createActionRegistry({ first, second });

    const results = await executeActions(
      registry,
      [{ type: 'first' }, { type: 'second' }],
      mockActionContext,
      mockDeps,
    );

    expect(results).toHaveLength(2);
    expect(results.every(r => r.success)).toBe(true);
    expect(order).toEqual(['first', 'second']);
  });

  it('runs analytics actions after primary actions but preserves result order', async () => {
    const order: string[] = [];
    const navigate: SDUIActionHandler = () => {
      order.push('navigate');
      return { success: true, data: 'nav' };
    };
    const track: SDUIActionHandler = () => {
      order.push('trackSelect');
      return { success: true, data: 'track' };
    };
    const registry = createActionRegistry({ navigate, trackSelect: track });

    const results = await executeActions(
      registry,
      [{ type: 'trackSelect', payload: { contentId: 'cta' } }, { type: 'navigate' }],
      mockActionContext,
      mockDeps,
    );

    expect(order).toEqual(['navigate', 'trackSelect']);
    expect(results[0].data).toBe('track');
    expect(results[1].data).toBe('nav');
  });

  it('analytics actions fire even if primary action fails', async () => {
    const order: string[] = [];
    const failing: SDUIActionHandler = () => {
      order.push('submit');
      throw new Error('API error');
    };
    const track: SDUIActionHandler = () => {
      order.push('trackSelect');
      return { success: true };
    };
    const registry = createActionRegistry({ submit: failing, trackSelect: track });

    const results = await executeActions(
      registry,
      [{ type: 'submit' }, { type: 'trackSelect' }],
      mockActionContext,
      mockDeps,
    );

    expect(order).toEqual(['submit', 'trackSelect']);
    expect(results[0].success).toBe(false);
    expect(results[1].success).toBe(true);
  });

  it('returns empty array for empty descriptors', async () => {
    const registry = createActionRegistry();
    const results = await executeActions(registry, [], mockActionContext, mockDeps);
    expect(results).toEqual([]);
  });
});

describe('default action registry', () => {
  afterEach(() => {
    const registry = getDefaultActionRegistry();
    for (const key of Object.keys(registry)) {
      delete registry[key];
    }
  });

  it('returns the default registry object', () => {
    const registry = getDefaultActionRegistry();
    expect(registry).toBeDefined();
    expect(typeof registry).toBe('object');
  });

  it('registerToDefaultActions adds to the default registry', () => {
    registerToDefaultActions('navigate', noop);
    const registry = getDefaultActionRegistry();
    expect(registry.navigate).toBe(noop);
  });
});
